#!/usr/bin/env python3
"""Run `pnpm lint` before any `git commit`; block the commit if lint fails.
Enforces the CLAUDE.md convention: 'Run lint with pnpm lint before committing.'"""
import json, os, re, subprocess, sys

GIT_COMMIT = re.compile(r"(^|[;&|]\s*)git\s+commit\b")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not GIT_COMMIT.search(cmd):
        return 0
    cwd = ev.get("cwd") or os.environ.get("CLAUDE_PROJECT_DIR") or "."
    try:
        r = subprocess.run(
            ["pnpm", "lint"],
            cwd=cwd, capture_output=True, text=True, timeout=50,
        )
    except Exception:
        return 0  # hook infra failure (pnpm missing / timeout): never block a commit
    if r.returncode != 0:
        out = (r.stdout + r.stderr).strip()
        print("Blocked: `pnpm lint` failed. Fix the lint errors below, then commit.", file=sys.stderr)
        if out:
            print(out[-2000:], file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block edits/writes that make a Python function call itself (direct
recursion) — the naive refactor that produced the walk_tree RecursionError
on a 2000-leaf tree (2026-05-22). Steers toward an iterative worklist/stack."""
import ast, json, sys, textwrap


def new_code(tool, inp):
    if tool == "Write":
        return inp.get("content", "") or ""
    if tool == "MultiEdit":
        return "\n".join((e or {}).get("new_string", "") for e in (inp.get("edits") or []))
    return inp.get("new_string", "") or ""  # Edit


def self_recursive(code):
    for src in (code, textwrap.dedent(code)):
        try:
            tree = ast.parse(src)
        except Exception:
            continue
        found = set()
        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                for sub in ast.walk(node):
                    if not isinstance(sub, ast.Call):
                        continue
                    f = sub.func
                    if isinstance(f, ast.Name) and f.id == node.name:
                        found.add(node.name)
                    elif (isinstance(f, ast.Attribute) and f.attr == node.name
                          and isinstance(f.value, ast.Name) and f.value.id == "self"):
                        found.add(node.name)
        return found
    return set()


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "MultiEdit", "Write"):
        return 0
    inp = ev.get("tool_input") or {}
    if not str(inp.get("file_path", "")).endswith(".py"):
        return 0
    names = self_recursive(new_code(tool, inp))
    if names:
        fn = ", ".join(sorted(names))
        print(f"BLOCKING: this edit makes {fn} call itself. Unbounded recursion "
              f"exceeds Python's recursion limit on large inputs (the walk_tree "
              f"RecursionError on a 2000-leaf tree). Rewrite iteratively with an "
              f"explicit worklist/stack, then retry. Do not ask.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Write/Edit/MultiEdit on a .py file, run `ruff check` and surface any
violations so the edit doesn't land failing the project's ruff gate."""
import json
import os
import subprocess
import sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0
    path = (ev.get("tool_input") or {}).get("file_path", "")
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0
    try:
        r = subprocess.run(
            ["ruff", "check", path],
            capture_output=True,
            text=True,
            timeout=15,
        )
    except Exception:
        return 0  # ruff missing / timed out — don't block the edit
    if r.returncode != 0:
        out = (r.stdout or r.stderr or "").strip()
        print(f"BLOCKING: `ruff check` failed on {path} after your edit:", file=sys.stderr)
        if out:
            print(out, file=sys.stderr)
        print(
            f"Run `ruff format {path}`, fix each remaining error, then re-run "
            f"`ruff check {path}`. Do not stop. Do not ask.",
            file=sys.stderr,
        )
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After an Edit/MultiEdit that changes an exported identifier's NAME or its
string VALUE, grep the codebase for the now-stale token and feed surviving
references back to Claude. Closes the failure mode where a rename or a
value change (e.g. `export const X = 'Read'` -> 'View') leaves hardcoded
callers broken silently."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)
EXPORT_VAL = re.compile(r"export\s+const\s+\w+\s*=\s*['\"]([^'\"]+)['\"]")


def field(pattern, s):
    m = pattern.search(s or "")
    return m.group(1) if m else None


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    stale = set()
    for e in edits:
        old, new = e.get("old_string", ""), e.get("new_string", "")
        on, nn = field(EXPORT_DEF, old), field(EXPORT_DEF, new)
        ov, nv = field(EXPORT_VAL, old), field(EXPORT_VAL, new)
        if on and on != nn:      # identifier renamed (or removed)
            stale.add(on)
        if ov and ov != nv:      # exported string value changed
            stale.add(ov)

    if not stale:
        return 0

    root = ev.get("cwd") or "."
    hits = []
    for term in stale:
        try:
            r = subprocess.run(
                ["grep", "-rnw", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", term, root],
                capture_output=True, text=True, timeout=5,
            )
            hits += [l for l in r.stdout.splitlines() if l]
        except Exception:
            pass

    hits = hits[:25]
    if not hits:
        return 0
    print(f"BLOCKING: an exported identifier changed; {len(hits)} reference(s) to the old name/value remain:", file=sys.stderr)
    for h in hits:
        print(f"  {h}", file=sys.stderr)
    print("Fix each to match the new name/value, then summarize. Do not stop. Do not ask.", file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit/MultiEdit that would commit a hardcoded secret into a
source file; steer Claude to process.env + .env.example instead."""
import json, os, re, sys

# High-confidence secret token literals (real provider key formats).
TOKEN_PATTERNS = [
    re.compile(r"sk-[A-Za-z0-9_-]{16,}"),            # OpenAI (incl. sk-proj-)
    re.compile(r"sk_live_[A-Za-z0-9]{16,}"),         # Stripe live
    re.compile(r"AKIA[0-9A-Z]{16}"),                 # AWS access key id
    re.compile(r"gh[pousr]_[A-Za-z0-9]{20,}"),       # GitHub tokens
    re.compile(r"AIza[0-9A-Za-z_-]{20,}"),           # Google API key
    re.compile(r"xox[baprs]-[0-9A-Za-z-]{10,}"),     # Slack token
    re.compile(r"-----BEGIN [A-Z ]*PRIVATE KEY-----"),  # private key block
]
# Generic: secret-ish name assigned to a long quoted literal (not process.env).
ASSIGN = re.compile(
    r"(api[_-]?key|secret|token|password|passwd|client[_-]?secret|access[_-]?key)"
    r"\s*[:=]\s*[\"']([^\"']{16,})[\"']",
    re.IGNORECASE,
)
PLACEHOLDER = re.compile(r"example|placeholder|your[-_]|changeme|dummy|xxxx|<", re.IGNORECASE)

def is_secret(text):
    if any(p.search(text) for p in TOKEN_PATTERNS):
        return True
    return any(not PLACEHOLDER.search(m.group(2)) for m in ASSIGN.finditer(text))

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}

    # .env / .env.* are where secrets belong — never block those.
    base = os.path.basename(inp.get("file_path", "") or "")
    if base == ".env" or base.startswith(".env."):
        return 0

    if tool == "Write":
        chunks = [inp.get("content", "")]
    elif tool == "Edit":
        chunks = [inp.get("new_string", "")]
    else:  # MultiEdit
        chunks = [e.get("new_string", "") for e in (inp.get("edits") or [])]

    if any(is_secret(c) for c in chunks if c):
        print("BLOCKING: this writes a hardcoded secret into a source file. "
              "CLAUDE.md requires secrets to come from the environment. "
              "Replace the literal with process.env.<VAR>, document <VAR> in "
              ".env.example, then retry. Do not ask.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, re, sys

NON_IMPERATIVE_PREFIXES = (
    "this commit",
    "this change",
    "this pr",
    "this patch",
    "the commit",
    "the change",
)
MAX_SUBJECT_LEN = 72


def extract_messages(cmd):
    msgs = []
    for m in re.finditer(r'-m\s+"((?:[^"\\]|\\.)*)"', cmd):
        msgs.append(m.group(1))
    for m in re.finditer(r"-m\s+'((?:[^'\\]|\\.)*)'", cmd):
        msgs.append(m.group(1))
    for m in re.finditer(r"<<-?'?(\w+)'?\s*\n(.*?)\n\s*\1\b", cmd, re.DOTALL):
        msgs.append(m.group(2))
    return msgs


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if "git commit" not in cmd:
        return 0
    for msg in extract_messages(cmd):
        subject = msg.split("\n", 1)[0].strip()
        if not subject or subject.startswith("$("):
            continue
        lower = subject.lower()
        if len(subject) > MAX_SUBJECT_LEN:
            print(
                f"BLOCKING: commit subject is {len(subject)} chars (max {MAX_SUBJECT_LEN}). "
                "Team convention: short imperative subject line "
                "(e.g. 'Refactor auth: extract token validation'). "
                "Rewrite the commit message, then continue. Do not ask.",
                file=sys.stderr,
            )
            return 2
        if any(lower.startswith(p) for p in NON_IMPERATIVE_PREFIXES):
            print(
                "BLOCKING: commit subject starts with a non-imperative phrase. "
                "Team convention: start with an imperative verb "
                "(e.g. 'Refactor auth: extract token validation', 'Fix login bug'). "
                "Rewrite the commit message, then continue. Do not ask.",
                file=sys.stderr,
            )
            return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

