#!/usr/bin/env python3
"""Block `git add` that would stage `.env` or use broad staging (-A / -a / .)."""
import json, re, sys

GIT_ADD = re.compile(r"\bgit\s+add\b")
ENV_TOKENS = re.compile(r"\.env(?:\.\w+)?")
BROAD_STAGE = re.compile(r"\bgit\s+add\s+(-A\b|-a\b|\.\s*$|\.\s+)")

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not GIT_ADD.search(cmd):
        return 0
    bad = [t for t in ENV_TOKENS.findall(cmd) if t != ".env.example"]
    if bad:
        print(
            f"BLOCKING: refusing to `git add` env file(s) {bad}. "
            "CLAUDE.md forbids committing a real `.env`. "
            "Stage other files by explicit path. Do not retry.",
            file=sys.stderr,
        )
        return 2
    if BROAD_STAGE.search(cmd):
        print(
            "BLOCKING: broad `git add` (-A / -a / .) can stage `.env` which CLAUDE.md forbids. "
            "Stage specific files by name. Do not retry without explicit paths.",
            file=sys.stderr,
        )
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
import json, sys, os, subprocess, shutil


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "Write", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0

    if shutil.which("ruff"):
        cmd = ["ruff", "check", "--select=F821,F822,F823", "--no-fix", "--quiet", path]
    elif shutil.which("pyflakes"):
        cmd = ["pyflakes", path]
    else:
        return 0

    try:
        result = subprocess.run(cmd, capture_output=True, text=True, timeout=10)
    except Exception:
        return 0

    if result.returncode != 0:
        output = (result.stdout + result.stderr).strip()
        if output:
            msg = (
                f"BLOCKING: static analysis found undefined-name issues in {path}:\n"
                f"{output}\n\n"
                f"Fix each reported name (define it, import it, or correct the typo) before continuing. "
                f"Do not stop until the file passes the check."
            )
            print(msg, file=sys.stderr)
            return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
